var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');
var id = String(data.id || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId');
}
if (!uuidRegex.test(id)) {
  throw new Error('Invalid id');
}

var query = "SELECT b.*, m.nom as membre_nom, m.prenom as membre_prenom, m.poste as membre_poste, m.departement as membre_departement FROM rh_bulletins_paie b LEFT JOIN equipe_members m ON b.member_id = m.id WHERE b.tenant_id = '" + esc(tenantId) + "' AND b.id = '" + esc(id) + "';";

return [{json: {query: query}}];

const row = $input.first().json;
if (!row || !row.id) {
  return [{json: {success: false, error: 'Bulletin non trouvé'}}];
}

// Parse les cotisations détaillées depuis le commentaire si disponible
var detailCotisations = null;
if (row.commentaire) {
  try {
    var parsed = JSON.parse(row.commentaire);
    if (parsed.cotisations || parsed.detail) {
      detailCotisations = parsed;
    }
  } catch(e) {
    // commentaire est du texte libre, pas du JSON
  }
}

var result = {
  id: row.id,
  memberId: row.member_id,
  membreNom: ((row.membre_nom || '') + ' ' + (row.membre_prenom || '')).trim(),
  membrePoste: row.membre_poste || null,
  membreDepartement: row.membre_departement || null,
  mois: Number(row.mois || 0),
  annee: Number(row.annee || 0),
  periode: String(row.mois || 0).padStart(2, '0') + '/' + (row.annee || ''),
  salaireBase: Number(row.salaire_base || 0),
  primes: Number(row.primes || 0),
  salaireBrut: Number(row.salaire_base || 0) + Number(row.primes || 0),
  deductions: Number(row.deductions || 0),
  chargesPatronales: Number(row.charges_patronales || 0),
  chargesSalariales: Number(row.charges_salariales || 0),
  netAPayer: Number(row.net_a_payer || 0),
  netImposable: Number(row.net_imposable || 0),
  coutTotal: Number(row.salaire_base || 0) + Number(row.primes || 0) + Number(row.charges_patronales || 0),
  statut: row.statut || 'brouillon',
  commentaire: detailCotisations ? null : (row.commentaire || null),
  detailCotisations: detailCotisations,
  createdAt: row.created_at,
  updatedAt: row.updated_at
};

return [{json: {success: true, data: result}}];
